// Acid Candy — osc layers multiplied for pattern, colorama feedback cycling
speed = 0.6

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// three osc mult'd = complex web pattern
osc(10, 0.1, 2.5)
  .mult(osc(15, 0.08, 1.5).rotate(() => time * 0.04))
  .mult(osc(7, 0.06, 3.0).rotate(() => time * -0.03))
  .color(
    () => 0.8 + low() * 1.0,
    () => 0.4 + mid() * 0.9,
    () => 0.6 + high() * 0.8
  )
  .modulate(noise(2, 0.2), 0.04)
  // feedback with HEAVY colorama = colors cycle every frame
  .blend(
    src(o0)
      .colorama(() => 0.005 + amp() * 0.01)
      .hue(() => low() * 0.01),
    0.82
  )
  .saturate(() => 1.2 + low() * 0.5)
  .contrast(() => 1.03 + low() * 0.1)
  .brightness(() => 0.03 + low() * 0.03)
  .out(o0)
